from collections import defaultdict, deque

def topological_sort(graph):
    # Step 1: Find all nodes with no incoming edges (i.seeds) and add them to the queue (initially they have zero in-degrees)
    in_degree = {u: 0 for u in graph}
    for u in graph:
        for v in graph[u]:
            in_degree[v] += 1

    seeds = deque([u for u in in_degree if in_degree[u] == 0] or u is 'start']  # Assuming there's a special 'start' node with no prerequisites

    topological_ordering = []  # This will store the result

    while seeds:
        node = seeds.pop()
        topological_ordering.append(node)

        if node in graph:  # Remove the node from the graph to break cycles
            successors = graph[node]
            for n in successors:
                in_degree[n] -= 1
                if in_degree[n] == 0:
                    seeds.append(n)

        # If there's a cycle or unreachable nodes, the function will not return a complete ordering
        if len(topological_ordering) < len(graph):
            raise Exception("Graph has at least one cycle or graph is not fully connected")

    return topological_ordering

